import{_ as a,o,c as s,a0 as t}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Assign or Remove Roles","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/assign-roles.md","filePath":"how-to/assign-roles.md"}'),n={name:"how-to/assign-roles.md"};function i(r,e,l,d,c,h){return o(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="assign-or-remove-roles" tabindex="-1">Assign or Remove Roles <a class="header-anchor" href="#assign-or-remove-roles" aria-label="Permalink to &quot;Assign or Remove Roles&quot;">​</a></h1><p>Use the assignments editor when one user needs access to a kingdom, an alliance, or more than one place at the same time. This is the normal way to give someone <code>King</code>, <code>Alliance Leader</code>, <code>Co-Leader</code>, or <code>Alliance Player</code> access after the account already exists.</p><blockquote><p>Screenshot placeholder: admin-assignments.png</p></blockquote><h2 id="open-the-assignments-editor" tabindex="-1">Open the assignments editor <a class="header-anchor" href="#open-the-assignments-editor" aria-label="Permalink to &quot;Open the assignments editor&quot;">​</a></h2><ol><li>Open <strong>Admin</strong>.</li><li>Find the user in <strong>Users</strong>.</li><li>Select <strong>Edit</strong>.</li><li>Use <strong>Current Assignments</strong> to review what they already have.</li><li>Use <strong>Add Assignment</strong> to add another role.</li></ol><h2 id="add-an-assignment" tabindex="-1">Add an assignment <a class="header-anchor" href="#add-an-assignment" aria-label="Permalink to &quot;Add an assignment&quot;">​</a></h2><ol><li>Pick the <strong>Kingdom</strong> if the role needs kingdom or alliance scope.</li><li>Pick the <strong>Alliance</strong> if the role is alliance-based.</li><li>Choose the role.</li><li>Select <strong>Add assignment</strong>.</li></ol><p>Use the exact UI labels:</p><ul><li><code>King</code></li><li><code>Alliance Leader</code></li><li><code>Co-Leader</code></li><li><code>Alliance Player</code></li></ul><p><code>Supreme Admin</code> is not added here. That is handled as a global account setting.</p><h2 id="remove-an-assignment" tabindex="-1">Remove an assignment <a class="header-anchor" href="#remove-an-assignment" aria-label="Permalink to &quot;Remove an assignment&quot;">​</a></h2><p>Use the delete button beside the assignment in <strong>Current Assignments</strong>.</p><p>Before you remove one, check whether it is the user&#39;s only management role or whether it was created by someone with tighter ownership rules.</p><h2 id="guard-messages-you-may-see" tabindex="-1">Guard messages you may see <a class="header-anchor" href="#guard-messages-you-may-see" aria-label="Permalink to &quot;Guard messages you may see&quot;">​</a></h2><p>These messages are important safety checks, not bugs:</p><ul><li><code>You cannot remove your own role because it would lock you out.</code></li><li><code>At least one active supreme admin must remain.</code></li><li><code>You can only remove role assignments that you created.</code></li></ul><h2 id="what-these-guards-mean" tabindex="-1">What these guards mean <a class="header-anchor" href="#what-these-guards-mean" aria-label="Permalink to &quot;What these guards mean&quot;">​</a></h2><p><code>You cannot remove your own role because it would lock you out.</code></p><ul><li>You tried to remove your own last management access.</li><li>Add or keep another active management assignment before removing this one.</li></ul><p><code>At least one active supreme admin must remain.</code></p><ul><li>The system will not let the final active <code>Supreme Admin</code> lose that access.</li><li>Another <code>Supreme Admin</code> must exist and stay active first.</li></ul><p><code>You can only remove role assignments that you created.</code></p><ul><li>This applies to <code>Kings</code>.</li><li>A <code>King</code> can only remove assignments they originally created themselves.</li></ul><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>Add before you remove when you are reshaping someone&#39;s access.</li><li>Double-check the scope so a user is placed in the correct kingdom or alliance.</li><li>If a person works in more than one alliance, keep one account and add assignments instead of making duplicate users.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./create-user.html">Create a User</a></li><li><a href="./edit-user.html">Edit a User &amp; Reset Their Password</a></li><li><a href="./delete-user.html">Delete a User</a></li><li><a href="./../roles/protection-rules.html">Safety Rules You&#39;ll Run Into</a></li></ul>',27)])])}const g=a(n,[["render",i]]);export{u as __pageData,g as default};
